import android.util.Log;

import java.io.IOException;
import java.nio.charset.StandardCharsets;

import okhttp3.Interceptor;
import okhttp3.Request;
import okhttp3.RequestBody;
import okhttp3.Response;
import okhttp3.ResponseBody;
import okio.Buffer;

public class LoggingInterceptor implements Interceptor {
    private static final String TAG = "NetworkLogger";

    @Override
    public Response intercept(Chain chain) throws IOException {
        Request request = chain.request();

        // Log the request details
        logRequest(request);

        long startTime = System.nanoTime();
        Response response = chain.proceed(request);
        long endTime = System.nanoTime();

        // Calculate time taken for the network call
        double duration = (endTime - startTime) / 1e6d;

        // Log the response details
        logResponse(response, duration);

        return response;
    }

    private void logRequest(Request request) {
        Log.d(TAG, "----------Request Start----------");
        Log.d(TAG, "URL: " + request.url());
        Log.d(TAG, "Method: " + request.method());

        // Log headers
        for (String headerName : request.headers().names()) {
            Log.d(TAG, headerName + ": " + request.header(headerName));
        }

        // Log request body if it's not null and is text-based
        RequestBody requestBody = request.body();
        if (requestBody != null && requestBody.contentType() != null && 
            requestBody.contentType().toString().contains("application/json")) {
            Buffer buffer = new Buffer();
            requestBody.writeTo(buffer);
            String body = buffer.readUtf8();
            Log.d(TAG, "Request Body: " + body);
        }

        Log.d(TAG, "----------Request End----------");
    }

    private void logResponse(Response response, double duration) throws IOException {
        ResponseBody responseBody = response.body();

        Log.d(TAG, "----------Response Start----------");
        Log.d(TAG, "Status Code: " + response.code());
        Log.d(TAG, "Duration: " + String.format("%.2f", duration) + " ms");

        // Log headers
        for (String headerName : response.headers().names()) {
            Log.d(TAG, headerName + ": " + response.header(headerName));
        }

        // Log response body if it's not null and is text-based
        if (responseBody != null && responseBody.contentType() != null &&
            responseBody.contentType().toString().contains("application/json")) {
            String body = responseBody.string();
            Log.d(TAG, "Response Body: " + body);
            responseBody.close(); // Close the response body to avoid memory leaks
        }

        Log.d(TAG, "----------Response End----------");
    }
}